import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object
  const TOTAL_STEPS = 4;
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({ name: '', email: '', satisfaction: 0, features: [] as string[], comments: '' });
  const [emailError, setEmailError] = useState('');

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const canGoNext = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    if (step === 2) return formData.satisfaction > 0;
    return true;
  }, [step, formData]);

  const handleNext = () => setStep((prev) => Math.min(prev + 1, TOTAL_STEPS));
  const handleBack = () => setStep((prev) => Math.max(prev - 1, 1));
  const handleSubmit = () => {
    submit(formData);
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Survey Form</Heading>
          <Text>Step {step} of {TOTAL_STEPS}</Text>
          <Progress value={((step - 1) / (TOTAL_STEPS - 1)) * 100} />
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {step === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Input label="Name" value={formData.name} onChange={(v) => setFormData({...formData, name: v})} required />
              <Input label="Email" value={formData.email} onChange={(v) => { setFormData({...formData, email: v}); setEmailError(validateEmail(v) ? '' : 'Invalid email'); }} error={emailError} required />
            </Stack>
          )}
          {step === 2 && (
            <RadioGroup label="How satisfied are you?" value={formData.satisfaction.toString()} onChange={(v) => setFormData({...formData, satisfaction: parseInt(v)})} options={props.satisfactionLabels.map((l, i) => ({ label: l, value: (i + 1).toString() }))} />
          )}
          {step === 3 && (
            <Stack gap="var(--ggui-spacing-2)">
              <Text>Select your interests:</Text>
              {props.featureOptions.map((f) => (
                <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(c) => setFormData({...formData, features: c ? [...formData.features, f] : formData.features.filter(x => x !== f)})} />
              ))}
            </Stack>
          )}
          {step === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <TextArea label="Comments" value={formData.comments} onChange={(v) => setFormData({...formData, comments: v})} maxLength={500} />
              <Text>Characters: {formData.comments.length}/500</Text>
              <Divider />
              <Heading level={3}>Review</Heading>
              {['Name', 'Email', 'Satisfaction', 'Features', 'Comments'].map(field => (
                <Text key={field} onClick={() => setStep(field === 'Name' || field === 'Email' ? 1 : field === 'Satisfaction' ? 2 : field === 'Features' ? 3 : 4)}>
                  <strong>{field}:</strong> {field === 'Name' ? formData.name : field === 'Email' ? formData.email : field === 'Satisfaction' ? (formData.satisfaction > 0 && formData.satisfaction <= props.satisfactionLabels.length ? props.satisfactionLabels[formData.satisfaction - 1] : 'Not set') : field === 'Features' ? (formData.features.join(', ') || 'None') : (formData.comments || 'No comments')}
                </Text>
              ))}
          )}
        </Card>
        <Row gap="var(--ggui-spacing-4)">
          {step > 1 && <Button as={Clickable} onClick={handleBack} variant="secondary">Back</Button>}
          {step < TOTAL_STEPS ? (
            <Button as={Clickable} onClick={handleNext} disabled={!canGoNext}>Next</Button>
          ) : (
            <Button as={Clickable} onClick={handleSubmit} variant="primary">Submit</Button>
          )}
        </Row>
        </Stack>
      </Container>
    );
  }

