// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

// Place helper components here if needed
const PriorityBadge = ({ priority }: { priority?: 'low' | 'medium' | 'high' }) => {
  const color = priority === 'high' ? 'error' : priority === 'medium' ? 'warning' : 'success';
  return <Badge variant={color}>{priority || 'low'}</Badge>;
};

export default function Component(props: Props) {
  const [tasks, setTasks] = useState(props.tasks || []);
  const [addingTo, setAddingTo] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Actions
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate');

  // Streams
  const taskChanged = useStream<StreamTaskChanged>('taskChanged');

  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (!task?.id) return;

      if (action === 'delete') {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      } else if (action === 'create' || action === 'edit' || action === 'move') {
        setTasks((prev) => {
          const index = prev.findIndex((t) => t.id === task.id);
          if (index > -1) {
            const next = [...prev];
            next[index] = { ...next[index], ...task };
            return next;
          }
          return [...prev, task];
        });
      }
    }
  }, [taskChanged.latest]);

  const handleMove = (taskId: string, targetColumn: string) => {
    setTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, column: targetColumn } : t)));
    taskUpdate({ action: 'move', taskId, data: { column: targetColumn } });
  };

  const handleAddTask = (columnId: string) => {
    if (!newTaskTitle.trim()) return;
    const newTask = {
      id: Date.now().toString(),
      title: newTaskTitle,
      priority: newTaskPriority,
      column: columnId,
      assignee: 'Me',
      dueDate: new Date().toISOString().split('T')[0],
    };
    setTasks([...tasks, newTask]);
    taskUpdate({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setNewTaskTitle('');
    setAddingTo(null);
  };

  const stats = useMemo(() => {
    const total = tasks.length;
    const done = tasks.filter((t) => t.column === 'done').length;
    return { total, done };
  }, [tasks]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Row justify="between" align="center">
          <Heading level={1}>Task Board</Heading>
          <Row gap="var(--ggui-spacing-4)">
            <Badge variant="info">Total: {stats.total}</Badge>
            <Badge variant="success">Done: {stats.done}</Badge>
          </Row>
        </Row>

        <Row gap="var(--ggui-spacing-4)" align="start">
          {(props.columns || []).map((col) => (
            <Box key={col.id} background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-4)" borderRadius="var(--ggui-shape-radius-lg)" style={{ flex: 1 }}>
              <Stack gap="var(--ggui-spacing-4)">
                <Heading level={4}>
                  {col.name} ({tasks.filter((t) => t.column === col.id).length})
                </Heading>
                <Stack gap="var(--ggui-spacing-2)">
                  {tasks
                    .filter((t) => t.column === col.id)
                    .map((task) => (
                      <Card key={task.id} padding="var(--ggui-spacing-3)">
                        <Stack gap="var(--ggui-spacing-2)">
                          <Text weight="semibold">{task.title}</Text>
                          <Row gap="var(--ggui-spacing-2)" align="center">
                            <PriorityBadge priority={task.priority} />
                            <Avatar name={task.assignee || 'U'} size={24} />
                            <Spacer size="flex" />
                            <Dropdown
                              trigger={<Button variant="ghost" size="sm"><Icon name="more-vertical" size={16} /></Button>}
                              options={(props.columns || []).map((c) => ({ value: c.id || '', label: `Move to ${c.name}` }))}
                              onChange={(val) => task.id && handleMove(task.id, val)}
                            />
                          </Row>
                        </Stack>
                      </Card>
                    ))}
                </Stack>
                {addingTo === col.id ? (
                  <Card padding="var(--ggui-spacing-3)">
                    <Stack gap="var(--ggui-spacing-2)">
                      <Input label="Title" value={newTaskTitle} onChange={setNewTaskTitle} />
                      <Select label="Priority" value={newTaskPriority} onChange={(v: any) => setNewTaskPriority(v)} options={[{value: 'low', label: 'Low'}, {value: 'medium', label: 'Medium'}, {value: 'high', label: 'High'}]} />
                      <Row gap="var(--ggui-spacing-2)">
                        <Button variant="primary" onClick={() => handleAddTask(col.id || '')}>Add</Button>
                        <Button variant="ghost" onClick={() => setAddingTo(null)}>Cancel</Button>
                      </Row>
                    </Stack>
                  </Card>
                ) : (
                  <Button variant="outline" onClick={() => setAddingTo(col.id || '')} fullWidth>Add Task</Button>
                )}
              </Stack>
            </Box>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

