// Helper for rendering rating stars
function RatingStars(props: { rating: number }) {
  return (
    <Row gap="var(--ggui-spacing-1)">
      {[...Array(5)].map((_, i) => (
        <Icon
          key={i}
          name={i < Math.floor(props.rating) ? 'star' : 'star-outline'}
