export default function Component(props: Props) {
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = props.product.stock || 0;
  const isOutOfStock = stock <= 0;

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCart({ productId: props.product.id, quantity });
    }
  }, [addToCart, props.product.id, quantity]);

  const tabs = useMemo(() => [
    { key: 'description', label: 'Description', content: <Text>{props.product.description || 'No description available.'}</Text> },
    { key: 'specifications', label: 'Specifications', content: (
      <Table 
        columns={[{ key: 'key', header: 'Attribute' }, { key: 'value', header: 'Value' }]}
        data={(props.product.specifications || []).map((s: any) => ({ key: s.key, value: s.value }))}
      />
    )},
    { key: 'reviews', label: 'Reviews', content: (
      <Stack gap="var(--ggui-spacing-4)">
        {(props.product.reviews || []).map((r: any, i: number) => (
          <Card key={i} padding="var(--ggui-spacing-3)">
            <Stack gap="var(--ggui-spacing-1)">
              <Row justify="between">
                <Text variant="label">{r.author}</Text>
                <Text variant="caption">{r.date}</Text>
              </Row>
              <RatingStars rating={r.rating} />
              <Text>{r.text}</Text>
            </Stack>
          </Card>
        ))}
      </Stack>
    )},
  ], [props.product.description, props.product.specifications, props.product.reviews]);

  const addToCart = useAction<ActionAddToCartPayload>('addToCart');

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row gap="var(--ggui-spacing-8)" wrap>
          <Box background="var(--ggui-color-surfaceVariant)" padding="var(--ggui-spacing-6)" borderRadius="var(--ggui-shape-radius-lg)" style={{ flex: 1, minWidth: '300px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
            <Heading level={2}>{props.product.name}</Heading>
          </Box>
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{props.product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">{props.product.currency || '$'}{props.product.price}</Text>
            <RatingStars rating={props.product.rating || 0} />
            <Badge variant={stock > 0 ? (stock < 5 ? 'warning' : 'success') : 'error'}>
              {stock > 0 ? (stock < 5 ? 'Low Stock' : 'In Stock') : 'Out of Stock'}
            </Badge>
          </Stack>
        </Row>

        <Tabs items={tabs} activeKey={activeTab} onChange={setActiveTab} />

        <Card padding="var(--ggui-spacing-6)" shadow="md">
          <Row gap="var(--ggui-spacing-4)" align="center" wrap>
            <Row align="center" gap="var(--ggui-spacing-2)">
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.max(1, quantity - 1))} disabled={isOutOfStock}>-</Button>
              <Input label="Quantity" type="number" value={quantity.toString()} onChange={(v) => setQuantity(Math.max(1, parseInt(v) || 1))} style={{ width: '60px' }} />
              <Button size="sm" variant="outline" onClick={() => setQuantity(Math.min(stock, quantity + 1))} disabled={isOutOfStock}>+</Button>
            </Row>
            <Button 
              variant="primary" 
              onClick={handleAddToCart} 
              disabled={isOutOfStock}
            >
              Add to Cart
            </Button>
          </Row>
        </Card>
      </Stack>
    </Container>
  );
}

