interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };





// Helper to format timestamp
const formatTime = (isoString: string) => {
  return new Date(isoString).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
};

// Helper component for message bubble
const MessageBubble = ({ sender, text, timestamp, isOwn }: { sender: string; text: string; timestamp: string; isOwn: boolean }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    <Box
      padding="var(--ggui-spacing-3)"
      borderRadius="var(--ggui-shape-radius-lg)"
      background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
    >
      <Text color={isOwn ? 'var(--ggui-color-onContainer)' : 'var(--ggui-color-onSurface)'}>{text}</Text>
    </Box>
    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
      {sender} • {formatTime(timestamp)}
    </Text>
  </Stack>
);

export default function Component(props: Props) {
  // Wire hooks
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage');
  const messageStream = useStream<StreamMessage>('message');
  const typingStream = useStream<StreamTyping>('typing');

  const [input, setInput] = useState('');
  const [messages, setMessages] = useState(props.messages || []);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Sync stream messages to local state
  useEffect(() => {
    if (messageStream.latest) {
      setMessages((prev) => [...prev, messageStream.latest!]);
    }
  }, [messageStream.latest]);

  // Auto-scroll
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, typingStream.latest]);

  const handleSend = () => {
    if (!input.trim()) return;
    const timestamp = new Date().toISOString();
    sendMessage({ text: input, timestamp });
    setMessages((prev) => [...prev, { sender: props.currentUser, text: input, timestamp }]);
    setInput('');
  };

  const activeTyping = typingStream.latest?.active ? typingStream.latest.sender : null;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-4)" shadow="md" radius="lg">
        <Stack gap="var(--ggui-spacing-4)">
          {/* Header */}
          <Row justify="between" align="center">
            <Stack>
              <Heading level={3}>{props.title}</Heading>
              <Badge variant="default" pill>{props.participantCount} participants</Badge>
            </Stack>
            {activeTyping && (
              <Text variant="caption" color="var(--ggui-color-primary-600)">{activeTyping} is typing...</Text>
            )}
          </Row>

          <Divider />

          {/* Message List */}
          <Box style={{ height: '400px', overflowY: 'auto' }} paddingY="var(--ggui-spacing-2)">
            <Stack gap="var(--ggui-spacing-4)">
              {messages.map((msg, i) => (
                <MessageBubble
                  key={i}
                  sender={msg.sender || 'Unknown'}
                  text={msg.text || ''}
                  timestamp={msg.timestamp || new Date().toISOString()}
                  isOwn={msg.sender === props.currentUser}
                />
              ))}
              <div ref={messagesEndRef} />
            </Stack>
          </Box>

          <Divider />

          {/* Input Area */}
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                placeholder="Type a message..."
                value={input}
                onChange={setInput}
                onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
              />
            </Box>
            <Button
              variant="primary"
              disabled={!input.trim()}
              onClick={handleSend}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

